-- Comprehensive exercise library seed (170 exercises)
-- Source: github.com/yuhonas/free-exercise-db (Public Domain)
-- Note: Uses ARRAY[] constructor to avoid quoting issues

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('3/4 Sit-Up', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie down on the floor and secure your feet. Your legs should be bent at the knees.','Place your hands behind or to the side of your head. You will begin with your back on the ground. This will be your starting position.','Flex your hips and spine to raise your torso toward your knees.','At the top of the contraction your torso should be perpendicular to the ground. Reverse the motion, going only ¾ of the way down.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Air Bike', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put your hands beside your head. Be careful however to not strain with the neck as you perform it. Now lift your shoulders into the crunch position.','Bring knees up to where they are perpendicular to the floor, with your lower legs parallel to the floor. This will be your starting position.','Now simultaneously, slowly go through a cycle pedal motion kicking forward with the right leg and bringing in the knee of the left leg. Bring your right elbow close to your left knee by crunching to the side, as you breathe out.','Go back to the initial position as you breathe in.','Crunch to the opposite side as you cycle your legs and bring closer your left elbow to your right knee and exhale.','Continue alternating in this manner until all of the recommended repetitions for each side have been completed.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bent-Knee Hip Raise', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lay flat on the floor with your arms next to your sides.','Now bend your knees at around a 75 degree angle and lift your feet off the floor by around 2 inches.','Using your lower abs, bring your knees in towards you as you maintain the 75 degree angle bend in your legs. Continue this movement until you raise your hips off of the floor by rolling your pelvis backward. Breathe out as you perform this portion of the movement. Tip: At the end of the movement your knees will be over your chest.','Squeeze your abs at the top of the movement for a second and then return to the starting position slowly as you breathe in. Tip: Maintain a controlled motion at all times.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bottoms Up', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin by lying on your back on the ground. Your legs should be straight and your arms at your side. This will be your starting position.','To perform the movement, tuck the knees toward your chest by flexing the hips and knees. Following this, extend your legs directly above you so that they are perpendicular to the ground. Rotate and elevate your pelvis to raise your glutes from the floor.','After a brief pause, return to the starting position.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Butt-Ups', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin a pushup position but with your elbows on the ground and resting on your forearms. Your arms should be bent at a 90 degree angle.','Arch your back slightly out rather than keeping your back completely straight.','Raise your glutes toward the ceiling, squeezing your abs tightly to close the distance between your ribcage and hips. The end result will be that you''ll end up in a high bridge position. Exhale as you perform this portion of the movement.','Lower back down slowly to your starting position as you breathe in. Tip: Don''t let your back sag downwards.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Judo Flip', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a rope attachment to a tower, and move the cable to the lowest pulley position. Stand with your side to the cable with a wide stance, and grab the rope with both hands.','Twist your body away from the pulley as you bring the rope over your shoulder like you''re performing a judo flip.','Shift your weight between your feet as you twist and crunch forward, pulling the cable downward.','Return to the starting position and repeat until failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Russian Twists', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a standard handle attachment, and position the cable to a middle pulley position.','Lie on a stability ball perpendicular to the cable and grab the handle with one hand. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable.','Grab the handle with both hands and fully extend your arms above your chest. You hands should be directly in-line with the pulley. If not, adjust the pulley up or down until they are.','Keep your hips elevated and abs engaged. Rotate your torso away from the pulley for a full-quarter rotation. Your body should be flat from head to knees.','Pause for a moment and in a slow and controlled manner reset to the starting position. You should still have side tension on the cable in the resting position.','Repeat the same movement to failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cocoons', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin by lying on your back on the ground. Your legs should be straight and your arms extended behind your head. This will be your starting position.','To perform the movement, tuck the knees toward your chest, rotating your pelvis to lift your glutes from the floor. As you do so, flex the spine, bringing your arms back over your head to perform a simultaneous crunch motion.','After a brief pause, return to the starting position.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cross-Body Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie flat on your back and bend your knees about 60 degrees.','Keep your feet flat on the floor and place your hands loosely behind your head. This will be your starting position.','Now curl up and bring your right elbow and shoulder across your body while bring your left knee in toward your left shoulder at the same time. Reach with your elbow and try to touch your knee. Exhale as you perform this movement. Tip: Try to bring your shoulder up towards your knee rather than just your elbow and remember that the key is to contract the abs as you perform the movement; not just to move the elbow.','Now go back down to the starting position as you inhale and repeat with the left elbow and the right knee.','Continue alternating in this manner until all prescribed repetitions are done.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dead Bug', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin lying on your back with your hands extended above you toward the ceiling.','Bring your feet, knees, and hips up to 90 degrees.','Exhale hard to bring your ribcage down and flatten your back onto the floor, rotating your pelvis up and squeezing your glutes. Hold this position throughout the movement. This will be your starting position.','Initiate the exercise by extending one leg, straightening the knee and hip to bring the leg just above the ground.','Maintain the position of your lumbar and pelvis as you perform the movement, as your back is going to want to arch.','Stay tight and return the working leg to the starting position.','Repeat on the opposite side, alternating until the set is complete.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Oblique Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Secure your legs at the end of the decline bench and slowly lay down on the bench.','Raise your upper body off the bench until your torso is about 35-45 degrees if measured from the floor.','Put one hand beside your head and the other on your thigh. This will be your starting position.','Raise your upper body slowly from the starting position while turning your torso to the left. Continue crunching up as you exhale until your right elbow touches your left knee. Hold this contracted position for a second. Tip: Focus on keeping your abs tight and keeping the movement slow and controlled.','Lower your body back down slowly to the starting position as you inhale.','After completing one set on the right for the recommended amount of repetitions, switch to your left side. Tip: Focus on really twisting your torso and feeling the contraction when you are in the up position.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Reverse Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie on your back on a decline bench and hold on to the top of the bench with both hands. Don''t let your body slip down from this position.','Hold your legs parallel to the floor using your abs to hold them there while keeping your knees and feet together. Tip: Your legs should be fully extended with a slight bend on the knee. This will be your starting position.','While exhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the bench. At the end of this movement your knees will be touching your chest.','Hold the contraction for a second and move your legs back to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Thigh Abductor', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['To begin, sit down on the abductor machine and select a weight you are comfortable with. When your legs are positioned properly, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.','Slowly press against the machine with your legs to move them away from each other while exhaling.','Feel the contraction for a second and begin to move your legs back to the starting position while breathing in. Note: Remember to keep your upper body stationary to prevent any injuries from occurring.','Repeat for the recommended amount of repetitions.'], ARRAY['abductors'], ARRAY['glutes'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Thigh Adductor', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['To begin, sit down on the adductor machine and select a weight you are comfortable with. When your legs are positioned properly on the leg pads of the machine, grip the handles on each side. Your entire upper body (from the waist up) should be stationary. This is the starting position.','Slowly press against the machine with your legs to move them towards each other while exhaling.','Feel the contraction for a second and begin to move your legs back to the starting position while breathing in. Note: Remember to keep your upper body stationary and avoid fast jerking motions in order to prevent any injuries from occurring.','Repeat for the recommended amount of repetitions.'], ARRAY['adductors'], ARRAY['glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Drag Curl', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Grab a barbell with a supinated grip (palms facing forward) and get your elbows close to your torso and back. This will be your starting position.','As you exhale, curl the bar up while keeping the elbows to the back as you Drag the bar up by keeping it in contact with your torso. Tip: As you can see, you will not be keeping the elbows pinned to your sides, but instead you will be bringing them back. Also, do not lift your shoulders.','Slowly go back to the starting position as you keep the bar in contact with the torso at all times.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('High Cable Curls', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['Stand between a couple of high pulleys and grab a handle in each arm. Position your upper arms in a way that they are parallel to the floor with the palms of your hands facing you. This will be your starting position.','Curl the handles towards you until they are next to your ears. Make sure that as you do so you flex your biceps and exhale. The upper arms should remain stationary and only the forearms should move. Hold for a second in the contracted position as you squeeze the biceps.','Slowly bring back the arms to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Alternate Hammer Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright and a dumbbell in each hand being held at arms length. The elbows should be close to the torso.','The palms of the hands should be facing your torso. This will be your starting position.','While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.','Slowly begin to bring the dumbbells back to starting position as your breathe in.','Repeat the movement with the left hand. This equals one repetition.','Continue alternating in this manner for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Alternate Incline Dumbbell Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position.','While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.','Slowly begin to bring the dumbbell back to starting position as your breathe in.','Repeat the movement with the left hand. This equals one repetition.','Continue alternating in this manner for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright while holding a barbell at a shoulder-width grip. The palm of your hands should be facing forward and the elbows should be close to the torso. This will be your starting position.','While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.','Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Curls Lying Against An Incline', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Lie against an incline bench, with your arms holding a barbell and hanging down in a horizontal line. This will be your starting position.','While keeping the upper arms stationary, curl the weight up as high as you can while squeezing the biceps. Breathe out as you perform this portion of the movement. Tip: Only the forearms should move. Do not swing the arms.','After a second contraction, slowly go back to the starting position as you inhale. Tip: Make sure that you go all of the way down.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Hammer Curls - Rope Attachment', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it.','Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary.','Put your elbows in by your side and keep them there stationary during the entire movement. Tip: Only the forearms should move; not your upper arms. This will be your starting position.','Using your biceps, pull your arms up as you exhale until your biceps touch your forearms. Tip: Remember to keep the elbows in and your upper arms stationary.','After a 1 second contraction where you squeeze your biceps, slowly start to bring the weight back to the original position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Preacher Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Place a preacher bench about 2 feet in front of a pulley machine.','Attach a straight bar to the low pulley.','Sit at the preacher bench with your elbow and upper arms firmly on top of the bench pad and have someone hand you the bar from the low pulley.','Grab the bar and fully extend your arms on top of the preacher bench pad. This will be your starting position.','Now start pilling the weight up towards your shoulders and squeeze the biceps hard at the top of the movement. Exhale as you perform this motion. Also, hold for a second at the top.','Now slowly lower the weight to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip EZ-Bar Curl with Band', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'pull', 'isolation', ARRAY['Attach a band to each end of the bar. Take the bar, placing a foot on the middle of the band. Stand upright with a narrow, supinated grip on the EZ bar. The elbows should be close to the torso. This will be your starting position.','While keeping the upper arms in place, flex the elbows to execute the curl. Exhale as the weight is lifted.','Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip EZ Bar Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright while holding an E-Z Curl Bar at the closer inner handle. The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar. The elbows should be close to the torso. This will be your starting position.','While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.','Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip Standing Barbell Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands, palms up and a few inches apart.','Stand with your torso straight and your head up. Your feet should be about shoulder width and your elbows close to your torso. This will be your starting position. Tip: You will keep your upper arms and elbows stationary throughout the movement.','Curl the bar up in a semicircular motion until the forearms touch your biceps. Exhale as you perform this portion of the movement and contract your biceps hard for a second at the top. Tip: Avoid bending the back or using swinging motions as you lift the weight. Only the forearms should move.','Slowly go back down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Concentration Curls', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit down on a flat bench with one dumbbell in front of you between your legs. Your legs should be spread with your knees bent and feet on the floor.','Use your right arm to pick the dumbbell up. Place the back of your right upper arm on the top of your inner right thigh. Rotate the palm of your hand until it is facing forward away from your thigh. Tip: Your arm should be extended and the dumbbell should be above the floor. This will be your starting position.','While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: At the top of the movement make sure that the little finger of your arm is higher than your thumb. This guarantees a good contraction. Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the dumbbells back to starting position as your breathe in. Caution: Avoid swinging motions at any time.','Repeat for the recommended amount of repetitions. Then repeat the movement with the left arm.'], ARRAY['biceps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Seated Calf Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['Place a block about 12 inches in front of a flat bench.','Sit on the bench and place the ball of your feet on the block.','Have someone place a barbell over your upper thighs about 3 inches above your knees and hold it there. This will be your starting position.','Raise up on your toes as high as possible as you squeeze the calves and as you breathe out.','After a second contraction, slowly go back to the starting position. Tip: To get maximum benefit stretch your calves as far as you can.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Calf Press', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the seat so that your legs are only slightly bent in the start position. The balls of your feet should be firmly on the platform.','Select an appropriate weight, and grasp the handles. This will be your starting position.','Straighten the legs by extending the knees, just barely lifting the weight from the stack. Your ankle should be fully flexed, toes pointing up. Execute the movement by pressing downward through the balls of your feet as far as possible.','After a brief pause, reverse the motion and repeat.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Calf Press On The Leg Press Machine', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance.','Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you without locking your knees. (Note: In some leg press units you can leave the safety bars on for increased safety. If your leg press unit allows for this, then this is the preferred method of performing the exercise.) Your torso and the legs should make perfect 90-degree angle. Now carefully place your toes and balls of your feet on the lower portion of the platform with the heels extending off. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.','Press on the platform by raising your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Seated One-Leg Calf Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Place a block on the floor about 12 inches from a flat bench.','Sit on a flat bench and place a dumbbell on your upper left thigh about 3 inches above your knee.','Now place the ball of your left foot on the block. This will be your starting position.','Raise your toes up as high as possible as you exhale and you contract your calf muscle. Hold the contraction for a second.','Slowly return to the starting position, stretching as far down as possible.','Repeat for your prescribed number of repetitions and then repeat with the right leg.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Rocking Standing Calf Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place it on the back of your shoulders (slightly below the neck).','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance. Also maintain a straight back and keep the knees with a slight bend; never locked. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending (other than the slight initial bend we created during positioning) at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Now lift your toes by contracting the tibia muscles in the front of the calves as you breathe out.','Hold for a second and bring them back down as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Calf Raise', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Sit on the machine and place your toes on the lower portion of the platform provided with the heels extending off. Choose the toe positioning of your choice (forward, in, or out) as per the beginning of this chapter.','Place your lower thighs under the lever pad, which will need to be adjusted according to the height of your thighs. Now place your hands on top of the lever pad in order to prevent it from slipping forward.','Lift the lever slightly by pushing your heels up and release the safety bar. This will be your starting position.','Slowly lower your heels by bending at the ankles until the calves are fully stretched. Inhale as you perform this movement.','Raise the heels by extending the ankles as high as possible as you contract the calves and breathe out. Hold the top contraction for a second.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Smith Machine Calf Raise', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Place a block or weight plate below the bar on the Smith machine. Set the bar to a position that best matches your height. Once the correct height is chosen and the bar is loaded, step onto the plates with the balls of your feet and place the bar on the back of your shoulders.','Take the bar with both hands facing forward. Rotate the bar to unrack it. This will be your starting position.','Raise your heels as high as possible by pushing off of the balls of your feet, flexing your calf at the top of the contraction. Your knees should remain extended. Hold the contracted position for a second before you start to go back down.','Return slowly to the starting position as you breathe in while lowering your heels.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Smith Machine Reverse Calf Raises', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the barbell on the smith machine to fit your height and align a raised platform right under the bar.','Stand on the platform with the heels of your feet secured on top of it with the balls of your feet extending off it. Position your toes facing forward with a shoulder width stance.','Now, place your shoulders under the barbell while maintaining the foot positioning described and push the barbell up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: The barbell on your back is only for balance purposes.','Raise the balls of your feet as you breathe out by extending your toes as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position for a second before you start to go back down.','Slowly go back down to the starting position as you breathe in by lowering the balls of your feet and toes.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Standing Barbell Calf Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the bar on the back of your shoulders (slightly below the neck).','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. The knees should be kept with a slight bend; never locked. This will be your starting position. Tip: For better range of motion you may also place the ball of your feet on a wooden block but be careful as this option requires more balance and a sturdy block.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Standing Calf Raises', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the padded lever of the calf raise machine to fit your height.','Place your shoulders under the pads provided and position your toes facing forward (or using any of the two other positions described at the beginning of the chapter). The balls of your feet should be secured on top of the calf block with the heels extending off it. Push the lever up by extending your hips and knees until your torso is standing erect. The knees should be kept with a slight bend; never locked. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Calf Raise On A Dumbbell', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Hang on to a sturdy object for balance and stand on a dumbbell handle, preferably one with round plates so that it rolls as in this manner you have to work harder to stabilize yourself; thus increasing the effectiveness of the exercise.','Now roll your foot slightly forward so that you can get a nice stretch of the calf. This will be your starting position.','Lift the calf as you roll your foot over the top of the handle so that you get a full extension. Exhale during the execution of this movement. Contract the calf hard at the top and hold for a second. Tip: As you come up, roll the dumbbell slightly backward.','Now inhale as you roll the dumbbell slightly forward as you come down to get a better stretch.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Standing Dumbbell Calf Raise', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Stand with your torso upright holding two dumbbells in your hands by your sides. Place the ball of the foot on a sturdy and stable wooden board (that is around 2-3 inches tall) while your heels extend off and touch the floor. This will be your starting position.','With the toes pointing either straight (to hit all parts equally), inwards (for emphasis on the outer head) or outwards (for emphasis on the inner head), raise the heels off the floor as you exhale by contracting the calves. Hold the top contraction for a second.','As you inhale, go back to the starting position by slowly lowering the heels.','Repeat for the recommended amount of times.'], ARRAY['calves'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Alternating Floor Press', 'kettlebells', true, 'kettlebells', 'beginner', 'push', 'compound', ARRAY['Lie on the floor with two kettlebells next to your shoulders.','Position one in place on your chest and then the other, gripping the kettlebells on the handle with the palms facing forward.','Extend both arms, so that the kettlebells are being held above your chest. Lower one kettlebell, bringing it to your chest and turn the wrist in the direction of the locked out kettlebell.','Raise the kettlebell and repeat on the opposite side.'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Bench Press - Medium Grip', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Lie back on a flat bench. Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','From the starting position, breathe in and begin coming down slowly until the bar touches your middle chest.','After a brief pause, push the bar back to the starting position as you breathe out. Focus on pushing the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position at the top of the motion, hold for a second and then start coming down slowly again. Tip: Ideally, lowering the weight should take about twice as long as raising it.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Incline Bench Press - Medium Grip', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Lie back on an incline bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on you upper chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly again. Tip: it should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Chest Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.','Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.','After pausing at full extension, return to th starting position, keeping tension on the cables.','You can also execute this movement with your back off the pad, at an incline or decline, or alternate hands.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Barbell Bench Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and slowly lay down on the bench.','Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.','As you breathe in, come down slowly until you feel the bar on your lower chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Dumbbell Bench Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','Once you are laying down, move the dumbbells in front of you at shoulder width.','Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.','Bring down the weights slowly to your side as you breathe out. Keep full control of the dumbbells at all times. Tip: Throughout the motion, the forearms should always be perpendicular to the floor.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up..','Repeat the movement for the prescribed amount of repetitions of your training program.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Dumbbell Flyes', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.','With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.','Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.','Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Push-Up', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Move your feet up to a box or bench. This will be your starting position.','Next, lower yourself downward until your chest almost touches the floor as you inhale.','Now breathe out and press your upper body back up to the starting position while squeezing your chest.','After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Decline Smith Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place a decline bench underneath the Smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms extended. This will be your starting position.','As you inhale, lower the bar under control by allowing the elbows to flex, lightly contacting the torso.','After a brief pause, bring the bar back to the starting position by extending the elbows, exhaling as you do so.','Repeat the movement for the prescribed amount of repetitions.','When the set is complete, lock the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Bench Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other.','Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.','Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. The dumbbells should be just to the sides of your chest, with your upper arm and forearm creating a 90 degree angle. Be sure to maintain full control of the dumbbells at all times. This will be your starting position.','Then, as you breathe out, use your chest to push the dumbbells up. Lock your arms at the top of the lift and squeeze your chest, hold for a second and then begin coming down slowly. Tip: Ideally, lowering the weight should take about twice as long as raising it.','Repeat the movement for the prescribed amount of repetitions of your training program.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Bench Press with Neutral Grip', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Take a dumbbell in each hand and lay back onto a flat bench. Your feet should be flat on the floor and your shoulder blades retracted.','Maintaining a neutral grip, palms facing each other, begin with your arms extended directly above you, perpendicular to the floor. This will be your starting position.','Begin the movement by flexing the elbow, lowering the upper arms to the side. Descend until the dumbbells are to your torso.','Pause, then extend the elbow and return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Extended Range One-Arm Kettlebell Floor Press', 'kettlebells', true, 'kettlebells', 'beginner', 'push', 'compound', ARRAY['Lie on the floor and position a kettlebell for one arm to press. The kettlebell should be held by the handle. The leg on the same side that you are pressing should be bent, with the knee crossing over the midline of the body.','Press the kettlebell by extending the elbow and adducting the arm, pressing it above your body. Return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bottoms-Up Clean From The Hang Position', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Initiate the exercise by standing upright with a kettlebell in one hand.','Swing the kettlebell back forcefully and then reverse the motion forcefully. Crush the kettlebell handle as hard as possible and raise the kettlebell to your shoulder.'], ARRAY['forearms'], ARRAY['biceps','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Wrist Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing a flat bench in front of a low pulley cable that has a straight bar attachment.','Use your arms to grab the cable bar with a narrow to shoulder width supinated grip (palms up) and bring them up so that your forearms are resting against the top of your thighs. Your wrists should be hanging just beyond your knees.','Start out by curling your wrist upwards and exhaling. Keep the contraction for a second.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Finger Curls', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart. This will be your starting position.','Lower the bar as far as possible by extending the fingers. Allowing the bar to roll down the hands, catch the bar with the final joint in the fingers.','Now curl bar up as high as possible by closing your hands while exhaling. Hold the contraction at the top.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Palms-Down Dumbbell Wrist Curl Over A Bench', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Palms-Down Wrist Curl Over A Bench', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a pronated grip (palms down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Palms-Up Barbell Wrist Curl Over A Bench', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Palms-Up Dumbbell Wrist Curl Over A Bench', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Dumbbell Palms-Down Wrist Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on the floor in front of a flat bench.','Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.','Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing down. Your wrists should be hanging over the edge of your thighs.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.','When finished, simply lower the dumbbells to the floor.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Dumbbell Palms-Up Wrist Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing two dumbbells on the floor in front of a flat bench.','Sit down on the edge of the flat bench with your legs at about shoulder width apart. Make sure to keep your feet on the floor.','Use your arms to grab both of the dumbbells and bring them up so that your forearms are resting against your thighs with the palms of the hands facing up. Your wrists should be hanging over the edge of your thighs.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise. Tip: Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.','When finished, simply lower the dumbbells to the floor.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated One-Arm Dumbbell Palms-Up Wrist Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit on a flat bench with a dumbbell in your right hand.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your right forearm on top of your upper right thigh with your palm up. Tip: Make sure that the front of the wrist lies on top of your knees. This will be your starting position.','Lower the dumbbell as far as possible as you keep a tight grip on the dumbbell. Inhale as you perform this movement.','Now curl the dumbbell as high as possible as you contract the forearms and as you exhale. Keep the contraction for a second before you lower again. Tip: The only movement should happen at the wrist.','Perform for the recommended amount of repetitions, switch arms and repeat the movement.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Palm-Up Barbell Wrist Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands and your palms facing up; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your forearms on top of your upper thighs with your palms up. Tip: Make sure that the front of the wrists lay on top of your knees. This will be your starting position.','Lower the bar as far as possible while inhaling and keeping a tight grip.','Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Palms-Down Barbell Wrist Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands and your palms facing down; hands spaced about shoulder width.','Place your feet flat on the floor, at a distance that is slightly wider than shoulder width apart.','Lean forward and place your forearms on top of your upper thighs with your palms down. Tip: Make sure that the back of the wrists lay on top of your knees. This will be your starting position.','Lower the bar as far as possible while inhaling and keeping a tight grip.','Now curl bar up as high as possible while flexing the forearms and exhaling. Hold the contraction at the top for a second and Tip: Only the wrist should move.'], ARRAY['forearms'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Flutter Kicks', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['On a flat bench lie facedown with the hips on the edge of the bench, the legs straight with toes high off the floor and with the arms on top of the bench holding on to the front edge.','Squeeze your glutes and hamstrings and straighten the legs until they are level with the hips. This will be your starting position.','Start the movement by lifting the left leg higher than the right leg.','Then lower the left leg as you lift the right leg.','Continue alternating in this manner (as though you are doing a flutter kick in water) until you have done the recommended amount of repetitions for each leg. Make sure that you keep a controlled movement at all times. Tip: You will breathe normally as you perform this movement.'], ARRAY['glutes'], ARRAY['hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Glute Kickback', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Kneel on the floor or an exercise mat and bend at the waist with your arms extended in front of you (perpendicular to the torso) in order to get into a kneeling push-up position but with the arms spaced at shoulder width. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.','As you exhale, lift up your right leg until the hamstrings are in line with the back while maintaining the 90-degree angle bend. Contract the glutes throughout this movement and hold the contraction at the top for a second. Tip: At the end of the movement the upper leg should be parallel to the floor while the calf should be perpendicular to it.','Go back to the initial position as you inhale and now repeat with the left leg.','Continue to alternate legs until all of the recommended repetitions have been performed.'], ARRAY['glutes'], ARRAY['hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Pull Through', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Begin standing a few feet in front of a low pulley with a rope or handle attached. Face away from the machine, straddling the cable, with your feet set wide apart.','Begin the movement by reaching through your legs as far as possible, bending at the hips. Keep your knees slightly bent. Keeping your arms straight, extend through the hip to stand straight up. Avoid pulling upward through the shoulders; all of the motion should originate through the hips.'], ARRAY['glutes'], ARRAY['hamstrings','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Step-up with Knee Raise', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Stand facing a box or bench of an appropriate height with your feet together. This will be your starting position.','Begin the movement by stepping up, putting your left foot on the top of the bench. Extend through the hip and knee of your front leg to stand up on the box. As you stand on the box with your left leg, flex your right knee and hip, bringing your knee as high as you can.','Reverse this motion to step down off the box, and then repeat the sequence on the opposite leg.'], ARRAY['glutes'], ARRAY['hamstrings','quadriceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Glute Bridge', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin seated on the ground with a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise. Roll the bar so that it is directly above your hips, and lay down flat on the floor.','Begin the movement by driving through with your heels, extending your hips vertically through the bar. Your weight should be supported by your upper back and the heels of your feet.','Extend as far as possible, then reverse the motion to return to the starting position.'], ARRAY['glutes'], ARRAY['calves','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Hip Thrust', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin seated on the ground with a bench directly behind you. Have a loaded barbell over your legs. Using a fat bar or having a pad on the bar can greatly reduce the discomfort caused by this exercise.','Roll the bar so that it is directly above your hips, and lean back against the bench so that your shoulder blades are near the top of it.','Begin the movement by driving through your feet, extending your hips vertically through the bar. Your weight should be supported by your shoulder blades and your feet. Extend as far as possible, then reverse the motion to return to the starting position.'], ARRAY['glutes'], ARRAY['calves','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Kneeling Jump Squat', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier.','Sit back with your hips until your glutes touch your feet, keeping your head and chest up.','Explode up with your hips, generating enough power to land with your feet flat on the floor.','Continue with the squat by driving through your heels and extending the knees to come to a standing position.'], ARRAY['glutes'], ARRAY['calves','hamstrings','quadriceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Kneeling Squat', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight.','With your head looking forward, sit back with your butt until you touch your calves.','Reverse the motion, returning the torso to an upright position.'], ARRAY['glutes'], ARRAY['abdominals','hamstrings','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Butt Lift (Bridge)', 'body only', true, 'body only', 'beginner', 'push', 'isolation', ARRAY['Lie flat on the floor on your back with the hands by your side and your knees bent. Your feet should be placed around shoulder width. This will be your starting position.','Pushing mainly with your heels, lift your hips off the floor while keeping your back straight. Breathe out as you perform this part of the motion and hold at the top for a second.','Slowly go back to the starting position as you breathe in.'], ARRAY['glutes'], ARRAY['hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Leg Lift', 'body only', true, 'body only', 'beginner', 'push', 'isolation', ARRAY['While standing up straight with both feet next to each other at around shoulder width, grab a sturdy surface such as the sides of a squat rack or the top of a chair to brace yourself and keep balance.','With or without an ankle weight, lift one leg behind you as if performing a leg curl but standing up while keeping the other leg straight. Breathe out as you perform this movement.','Slowly bring the raised leg back to the floor as you breathe in.','Repeat for the recommended amount of repetitions.','Repeat the movement with the opposite leg.'], ARRAY['glutes'], ARRAY['hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Single Leg Glute Bridge', 'body only', true, 'body only', 'beginner', 'push', 'isolation', ARRAY['Lay on the floor with your feet flat and knees bent.','Raise one leg off of the ground, pulling the knee to your chest. This will be your starting position.','Execute the movement by driving through the heel, extending your hip upward and raising your glutes off of the ground.','Extend as far as possible, pause and then return to the starting position.'], ARRAY['glutes'], ARRAY['hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('One-Legged Cable Kickback', 'cable', true, 'cable', 'intermediate', 'push', 'isolation', ARRAY['Hook a leather ankle cuff to a low cable pulley and then attach the cuff to your ankle.','Face the weight stack from a distance of about two feet, grasping the steel frame for support.','While keeping your knees and hips bent slightly and your abs tight, contract your glutes to slowly kick the working leg back in a semicircular arc as high as it will comfortably go as you breathe out. Tip: At full extension, squeeze your glutes for a second in order to achieve a peak contraction.','Now slowly bring your working leg forward, resisting the pull of the cable until you reach the starting position.','Repeat for the recommended amount of repetitions.','Switch legs and repeat the movement for the other side.'], ARRAY['glutes'], ARRAY['hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Clean Deadlift', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Begin standing with a barbell close to your shins. Your feet should be directly under your hips with your feet turned out slightly. Grip the bar with a double overhand grip or hook grip, about shoulder width apart. Squat down to the bar. Your spine should be in full extension, with a back angle that places your shoulders in front of the bar and your back as vertical as possible.','Begin by driving through the floor through the front of your heels. As the bar travels upward, maintain a constant back angle. Flare your knees out to the side to help keep them out of the bar''s path.','After the bar crosses the knees, complete the lift by driving the hips into the bar until your hips and knees are extended.'], ARRAY['hamstrings'], ARRAY['forearms','glutes','lower back','middle back','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Smith Machine Stiff-Legged Deadlift', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.','Lift the bar up by fully extending your arms while keeping your back straight. Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.','Keeping the knees stationary, lower the barbell to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement','Start bringing your torso up straight again as soon as you feel the hamstrings stretch by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['glutes','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Stiff-Legged Dumbbell Deadlift', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Grasp a couple of dumbbells holding them by your side at arm''s length.','Stand with your torso straight and your legs spaced using a shoulder width or narrower stance. The knees should be slightly bent. This is your starting position.','Keeping the knees stationary, lower the dumbbells to over the top of your feet by bending at the waist while keeping your back straight. Keep moving forward as if you were going to pick something from the floor until you feel a stretch on the hamstrings. Exhale as you perform this movement','Start bringing your torso up straight again by extending your hips and waist until you are back at the starting position. Inhale as you perform this movement.','Repeat for the recommended amount of repetitions.'], ARRAY['hamstrings'], ARRAY['glutes','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Alternating Hang Clean', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean one kettlebell to your shoulder and hold on to the other kettlebell in a hanging position. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so.','Lower the cleaned kettlebell to a hanging position and clean the alternate kettlebell. Repeat.'], ARRAY['hamstrings'], ARRAY['biceps','calves','forearms','glutes','lower back','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Clean', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on the floor close to the shins, take an overhand (or hook) grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.','Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.','As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.'], ARRAY['hamstrings'], ARRAY['calves','forearms','glutes','lower back','quadriceps','shoulders','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Double Kettlebell Alternating Hang Clean', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean one kettlebell to your shoulder and hold on to the other kettlebell.','With a fluid motion, lower the top kettlebell while driving the bottom kettlebell up.'], ARRAY['hamstrings'], ARRAY['biceps','calves','forearms','glutes','lower back','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Clean', 'dumbbell', true, 'dumbbell', 'intermediate', 'pull', 'compound', ARRAY['Begin standing with a dumbbell in each hand with your feet shoulder width apart.','Lower the weights to the floor by flexing at the hips and knees, pushing your hips back until the dumbbells reach the floor. This will be your starting position.','To initiate the movement, violently jump upward by extending the hips, knees, and ankles to acclerate the weights upward. Maintaining a neutral grip on the dumbbells, keep the arms straight until full extension is reached.','After full extension, rebend the hips and knees to receive the weight in a squat position. Allow the arms to bend, guiding the dumbbells to your shoulders.','Upon receiving the weight in the squat position, extend the hips and knees to finish in a standing position with the weights on your shoulders.'], ARRAY['hamstrings'], ARRAY['calves','forearms','glutes','lower back','quadriceps','shoulders','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Glute Ham Raise', 'machine', true, 'machine', 'intermediate', 'pull', 'compound', ARRAY['Begin by adjusting the equipment to fit your body. Place your feet against the footplate in between the rollers as you lie facedown. Your knees should be just behind the pad.','Start from the bottom of the movement. Keep your back arched as you begin the movement by flexing the knees. Drive your toes into the foot plate as you do so. Keep your upper body straight, and continue until your body is upright.','Return to the starting position, keeping your descent under control.'], ARRAY['hamstrings'], ARRAY['calves','glutes'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Good Morning', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with a bar on a rack at shoulder height. Rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Step back from the rack.','Begin by bending at the hips, moving them back as you bend over to near parallel. Keep your back arched and your cervical spine in proper alignment.','Reverse the motion by extending through the hips with your glutes and hamstrings. Continue until you have returned to the starting position.'], ARRAY['hamstrings'], ARRAY['abdominals','glutes','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Good Morning off Pins', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin with a bar on a rack at about the same height as your stomach. Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.','Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight. Slowly lower the weight back to the pins returning to the starting position.'], ARRAY['hamstrings'], ARRAY['abdominals','glutes','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Hang Snatch', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be at the hips. This will be your starting position.','Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.','Return to a standing position with the weight overhead. Follow by returning the weight to the ground under control.'], ARRAY['hamstrings'], ARRAY['abdominals','calves','forearms','glutes','lower back','quadriceps','shoulders','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Hang Snatch - Below Knees', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be just below the knees. This will be your starting position.','Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.','Return to a standing position with the weight overhead, and then return the weight to the floor under control.'], ARRAY['hamstrings'], ARRAY['abdominals','calves','forearms','glutes','lower back','quadriceps','shoulders','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Chin-Up', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.','As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.','Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','forearms','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip Front Lat Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.','Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.','As you have both arms extended in front of you - while holding the bar at the chosen grip width - bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary (only the arms should move). The forearms should do no other work except for holding the bar; therefore do not try to pull the bar down using the forearms.','After a second in the contracted position, while squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.','6. Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Kneeling High Pulley Row', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.','Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.','After pausing briefly, slowly return to the starting position.'], ARRAY['lats'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Kneeling Single-Arm High Pulley Row', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Attach a single handle to a high pulley and make your weight selection.','Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position.','Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you.','After a brief pause, return to the starting position.'], ARRAY['lats'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Leverage Iso Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['Load an appropriate weight onto the pins and adjust the seat height so that the handles are at chest level. Grasp the handles with either a neutral or pronated grip. This will be your starting position.','Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handles to the starting position. For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked.'], ARRAY['lats'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('One Arm Lat Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Select an appropriate weight and adjust the knee pad to help keep you down. Grasp the handle with a pronated grip. This will be your starting position.','Pull the handle down, squeezing your elbow to your side as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handle to the starting position.','For multiple repetitions, avoid completely returning the weight to keep tension on the muscles being worked.'], ARRAY['lats'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Pullups', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Shotgun Row', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Attach a single handle to a low cable.','After selecting the correct weight, stand a couple feet back with a wide-split stance. Your arm should be extended and your shoulder forward. This will be your starting position.','Perform the movement by retracting the shoulder and flexing the elbow. As you pull, supinate the wrist, turning the palm upward as you go.','After a brief pause, return to the starting position.'], ARRAY['lats'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Underhand Cable Pulldowns', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit down on a pull-down machine with a wide bar attached to the top pulley. Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.','Grab the pull-down bar with the palms facing your torso (a supinated grip). Make sure that the hands are placed closer than the shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','As you breathe out, pull the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the fully contracted position and keep the elbows close to your body. The upper torso should remain stationary as your bring the bar to you and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, while breathing in, slowly bring the bar back to the starting position when your arms are fully extended and the lats are fully stretched.','Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('V-Bar Pullup', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles.','Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position.','Using your lats, pull your torso up while leaning your head back slightly so that you do not hit yourself with the chin-up bar. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion.','After a second hold on the contracted position, slowly lower your body back to the starting position as you breathe in.','Repeat for the prescribed number of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Wide-Grip Lat Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.','Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the bar; therefore do not try to pull down the bar using the forearms.','After a second at the contracted position squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.','Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bent-Arm Barbell Pullover', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Lie on a flat bench with a barbell using a shoulder grip width.','Hold the bar straight over your chest with a bend in your arms. This will be your starting position.','While keeping your arms in the bent arm position, lower the weight slowly in an arc behind your head while breathing in until you feel a stretch on the chest.','At that point, bring the barbell back to the starting position using the arc through which the weight was lowered and exhale as you perform this movement.','Hold the weight on the initial position for a second and repeat the motion for the prescribed number of repetitions.'], ARRAY['lats'], ARRAY['chest','lats','shoulders','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Stiff Leg Barbell Good Morning', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position.','Keeping your legs stationary, move your torso forward by bending at the hips while inhaling. Lower your torso until it is parallel with the floor.','Begin to raise the bar as you exhale by elevating your torso back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['lower back'], ARRAY['glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Stand in front of a loaded barbell.','While keeping the back as straight as possible, bend your knees, bend forward and grasp the bar using a medium (shoulder width) overhand grip. This will be the starting position of the exercise. Tip: If it is difficult to hold on to the bar with this grip, alternate your grip or use wrist straps.','While holding the bar, start the lift by pushing with your legs while simultaneously getting your torso to the upright position as you breathe out. In the upright position, stick your chest out and contract the back by bringing the shoulder blades back. Think of how the soldiers in the military look when they are in standing in attention.','Go back to the starting position by bending at the knees while simultaneously leaning the torso forward at the waist while keeping the back straight. When the weights on the bar touch the floor you are back at the starting position and ready to perform another repetition.','Perform the amount of repetitions prescribed in the program.'], ARRAY['lower back'], ARRAY['calves','forearms','glutes','hamstrings','lats','middle back','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Deadlift with Bands', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['To deadlift with short bands, simply loop them over the bar before you start, and step into them to set up. For long bands, they will need to be anchored to a secure base, such as heavy dumbbells or a rack.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','middle back','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Deadlift with Chains', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift.','Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets. With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar.','Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','middle back','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Deficit Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin by having a platform or weight plates that you can stand on, usually 1-3 inches in height. Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','middle back','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Hyperextensions With No Hyperextension Bench', 'body only', true, 'body only', 'intermediate', 'pull', 'compound', ARRAY['With someone holding down your legs, slide yourself down to the edge a flat bench until your hips hang off the end of the bench. Tip: Your entire upper body should be hanging down towards the floor. Also, you will be in the same position as if you were on a hyperextension bench but the range of motion will be shorter due to the height of the flat bench vs. that of the hyperextension bench.','With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.','Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you almost touch the floor or you feel a nice stretch on the hamstrings (whichever comes first). Tip: Never round the back as you perform this exercise.','Slowly raise your torso back to the initial position as you exhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.','Repeat for the recommended amount of repetitions.'], ARRAY['lower back'], ARRAY['glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Rack Pull with Bands', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Attach bands to the base of the rack, or secure them with dumbbells. Attach the other end to the bar. You may need to choke the bands to provide tension.','Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.','With your head looking forward, extend through the hips and knees, pulling the weight up and back until lockout. Be sure to pull your shoulders back as you complete the movement. Return the weight to the pins and repeat.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','quadriceps','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Rack Pulls', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.','With your head looking forward, extend through the hips and knees, pulling the weight up and back until lockout. Be sure to pull your shoulders back as you complete the movement.','Return the weight to the pins and repeat.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Reverse Band Deadlift', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['Set the bar up in a power rack. Attach bands to the top of the rack, using either bands pegs or the frame itself. Attach the other end of the bands to the bar.','Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward.','After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['abductors','adductors','calves','glutes','hamstrings','quadriceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Good Mornings', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Set up a box in a power rack. The pins should be set at an appropriate height. Begin by stepping under the bar and placing it across the back of the shoulders, not on top of your traps. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders.','Remove the bar from the rack, creating a tight arch in your lower back. Keep your head facing forward. With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips until you are seated on the box. This will be your starting position.','Keeping the bar tight, bend forward at the hips as much as possible. If you set the pins to what would be parallel, you not only have a safety if you fail, but know when to stop.','Pause just above the pins and reverse the motion until your torso it upright.'], ARRAY['lower back'], ARRAY['glutes'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bent Over Barbell Row', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Holding a barbell with a pronated grip (palms facing down), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.','Now, while keeping the torso stationary, breathe out and lift the barbell to you. Keep the elbows close to the body and only use the forearms to hold the weight. At the top contracted position, squeeze the back muscles and hold for a brief pause.','Then inhale and slowly lower the barbell back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bent Over One-Arm Long Bar Row', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Put weight on one of the ends of an Olympic barbell. Make sure that you either place the other end of the barbell in the corner of two walls; or put a heavy object on the ground so the barbell cannot slide backward.','Bend forward until your torso is as close to parallel with the floor as you can and keep your knees slightly bent.','Now grab the bar with one arm just behind the plates on the side where the weight was placed and put your other hand on your knee. This will be your starting position.','Pull the bar straight up with your elbow in (to maximize back stimulation) until the plates touch your lower chest. Squeeze the back muscles as you lift the weight up and hold for a second at the top of the movement. Breathe out as you lift the weight. Tip: Do not allow for any swinging of the torso. Only the arm should move.','Slowly lower the bar to the starting position getting a nice stretch on the lats. Tip: Do not let the plates touch the floor. To ensure the best range of motion, I recommend using small plates (25-lb ones) as opposed to larger plates (like 35-45lb ones).','Repeat for the recommended amount of repetitions and switch arms.'], ARRAY['middle back'], ARRAY['biceps','lats','lower back','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bent Over Two-Dumbbell Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['With a dumbbell in each hand (palms facing your torso), bend your knees slightly and bring your torso forward by bending at the waist; as you bend make sure to keep your back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the dumbbells to your side (as you breathe out), keeping the elbows close to the body (do not exert any force with the forearm other than holding the weights). On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bent Over Two-Dumbbell Row With Palms In', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['With a dumbbell in each hand (palms facing each other), bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The weights should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the dumbbells to your side as you breathe out, squeezing your shoulder blades together. On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Incline Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Using a neutral grip, lean into an incline bench.','Take a dumbbell in each hand with a neutral grip, beginning with the arms straight. This will be your starting position.','Retract the shoulder blades and flex the elbows to row the dumbbells to your side.','Pause at the top of the motion, and then return to the starting position.'], ARRAY['middle back'], ARRAY['biceps','forearms','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Inverted Row', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Position a bar in a rack to about waist height. You can also use a smith machine.','Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.'], ARRAY['middle back'], ARRAY['lats'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Leverage High Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['Load an appropriate weight onto the pins and adjust the seat height so that you can just reach the handles above you. Adjust the knee pad to help keep you down. Grasp the handles with a pronated grip. This will be your starting position.','Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handles to the starting position.','For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked.'], ARRAY['middle back'], ARRAY['lats'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('One-Arm Dumbbell Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Choose a flat bench and place a dumbbell on each side of it.','Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.','Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position.','Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms.','Lower the resistance straight down to the starting position. Breathe in as you perform this step.','Repeat the movement for the specified amount of repetitions.','Switch sides and repeat again with the other arm.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('One-Arm Long Bar Row', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.','Stand next to the bar, and take a grip with one hand close to the collar. Using your hips and legs, rise to a standing position.','Assume a bent-knee stance with your hips back and your chest up. Your arm should be extended. This will be your starting position.','Pull the weight to your side by retracting the shoulder and flexing the elbow. Do not jerk the weight or cheat during the movement.','After a brief pause, return to the starting position.'], ARRAY['middle back'], ARRAY['biceps','lats'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Seated Cable Rows', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['For this exercise you will need access to a low pulley row machine with a V-bar. Note: The V-bar will enable you to have a neutral grip where the palms of your hands face each other. To get into the starting position, first sit down on the machine and place your feet on the front platform or crossbar provided making sure that your knees are slightly bent and not locked.','Lean over as you keep the natural alignment of your back and grab the V-bar handles.','With your arms extended pull back until your torso is at a 90-degree angle from your legs. Your back should be slightly arched and your chest should be sticking out. You should be feeling a nice stretch on your lats as you hold the bar in front of you. This is the starting position of the exercise.','Keeping the torso stationary, pull the handles back towards your torso while keeping the arms close to it until you touch the abdominals. Breathe out as you perform that movement. At that point you should be squeezing your back muscles hard. Hold that contraction for a second and slowly go back to the original position while breathing in.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Smith Machine Bent Over Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['Set the barbell attached to the smith machine to a height that is about 2 inches below your knees.','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up.','Now grasp the barbell using an overhand (pronated) grip and unlock it from the smith machine rack. Then let it hang directly in front of you as your arms hang extended perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['middle back'], ARRAY['biceps','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Straight Bar Bench Mid Rows', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Place a loaded barbell on the end of a bench. Standing on the bench behind the bar, take a medium, pronated grip. Stand with your hips back and chest up, maintaining a neutral spine. This will be your starting position.','Row the bar to your torso by retracting the shoulder blades and flexing the elbows. Use a controlled movement with no jerking.','After a brief pause, slowly return the bar to the starting position, ensuring to go all the way down.'], ARRAY['middle back'], ARRAY['biceps','lats'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Isometric Neck Exercise - Front And Back', 'body only', true, 'body only', 'beginner', 'static', 'isolation', ARRAY['With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head.','Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat with your hands placed on the back side of your head.'], ARRAY['neck'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Isometric Neck Exercise - Sides', 'body only', true, 'body only', 'beginner', 'static', 'isolation', ARRAY['With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head.','Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat with your right hand placed on the right side of your head.'], ARRAY['neck'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Side Split Squat', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Stand up straight while holding a barbell placed on the back of your shoulders (slightly below the neck). Your feet should be placed wide apart with the foot of the lead leg angled out to the side. This will be your starting position.','Lower your body towards the side of your angled foot by bending the knee and hip of your lead leg and while keeping the opposite leg only slightly bent. Breathe in as you lower your body.','Return to the starting position by extending the hip and knee of the lead leg. Breathe out as you perform this movement.','After performing the recommended amount of reps, repeat the movement with the opposite leg.'], ARRAY['quadriceps'], ARRAY['calves','hamstrings','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Squat', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack to just below shoulder level. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times and also maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).','Begin to slowly lower the bar by bending the knees and hips as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees. Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor with the heel of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Walking Lunge', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Begin standing with your feet shoulder width apart and a barbell across your upper back.','Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.','Drive through the heel of your lead foot and extend both knees to raise yourself back up.','Step forward with your rear foot, repeating the lunge on the opposite leg.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bodyweight Squat', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Stand with your feet shoulder width apart. You can place your hands behind your head. This will be your starting position.','Begin the movement by flexing your knees and hips, sitting back with your hips.','Continue down to full depth if you are able,and quickly reverse the motion until you return to the starting position. As you squat, keep your head and chest up and push your knees out.'], ARRAY['quadriceps'], ARRAY['glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bodyweight Walking Lunge', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Begin standing with your feet shoulder width apart and your hands on your hips.','Step forward with one leg, flexing the knees to drop your hips. Descend until your rear knee nearly touches the ground. Your posture should remain upright, and your front knee should stay above the front foot.','Drive through the heel of your lead foot and extend both knees to raise yourself back up.','Step forward with your rear foot, repeating the lunge on the opposite leg.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Deadlifts', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Move the cables to the bottom of the towers and select an appropriate weight. Stand directly in between the uprights.','To begin, squat down be flexing your hips and knees until you can reach the handles.','After grasping them, begin your ascent. Driving through your heels extend your hips and knees keeping your hands hanging at your side. Keep your head and chest up throughout the movement.','After reaching a full standing position, Return to the starting position and repeat.'], ARRAY['quadriceps'], ARRAY['forearms','glutes','hamstrings','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Chair Squat', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders.','Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs.','Move your feet forward about 18 inches in front of the bar. Position your legs using a shoulder width stance with the toes slightly pointed out. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.','Slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper and lower leg breaks 90 degrees.','Begin to raise the bar as you exhale by pushing the floor with the heels of your feet, extending the knees and returning to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Lunges', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Stand with your torso upright holding two dumbbells in your hands by your sides. This will be your starting position.','Step forward with your right leg around 2 feet or so from the foot being left stationary behind and lower your upper body down, while keeping the torso upright and maintaining balance. Inhale as you go down. Note: As in the other exercises, do not allow your knee to go forward beyond your toes as you come down, as this will put undue stress on the knee joint. Make sure that you keep your front shin perpendicular to the ground.','Using mainly the heel of your foot, push up and go back to the starting position as you exhale.','Repeat the movement for the recommended amount of repetitions and then perform with the left leg.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Squat', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Stand up straight while holding a dumbbell on each hand (palms facing the side of your legs).','Position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. This will be your starting position. Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section.','Begin to slowly lower your torso by bending the knees as you maintain a straight posture with the head up. Continue down until your thighs are parallel to the floor. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise your torso as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','lower back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Goblet Squat', 'kettlebells', true, 'kettlebells', 'beginner', 'push', 'compound', ARRAY['Stand holding a light kettlebell by the horns close to your chest. This will be your starting position.','Squat down between your legs until your hamstrings are on your calves. Keep your chest and head up and your back straight.','At the bottom position, pause and use your elbows to push your knees out. Return to the starting position, and repeat for 10-20 repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Hack Squat', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.','Position your legs in the platform using a shoulder width medium stance with the toes slightly pointed out. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Place your arms on the side handles of the machine and disengage the safety bars (which on most designs is done by moving the side handles from a facing front position to a diagonal position).','Now straighten your legs without locking the knees. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Begin to slowly lower the unit by bending the knees as you maintain a straight posture with the head up (back on the pad at all times). Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the unit as you exhale by pushing the floor with mainly with the heel of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Leg Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.','As you inhale, slowly lower the platform until your upper and lower legs make a 90-degree angle.','Pushing mainly with the heels of your feet and using the quadriceps go back to the starting position as you exhale.','Repeat for the recommended amount of repetitions and ensure to lock the safety pins properly once you are done. You do not want that platform falling on you fully loaded.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Alternating Cable Shoulder Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Move the cables to the bottom of the tower and select an appropriate weight.','Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.','Keeping your head and chest up, extend through the elbow to press one side directly over head.','After pausing at the top, return to the starting position and repeat on the opposite side.'], ARRAY['shoulders'], ARRAY['triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Anti-Gravity Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Place a bar on the ground behind the head of an incline bench.','Lay on the bench face down. With a pronated grip, pick the barbell up from the floor. Flex the elbows, performing a reverse curl to bring the bar near your chest. This will be your starting position.','To begin, press the barbell out in front of your head by extending your elbows. Keep your arms parallel to the ground throughout the movement.','Return to the starting position and repeat to complete the set.'], ARRAY['shoulders'], ARRAY['middle back','traps','triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Incline Shoulder Raise', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Lie back on an Incline Bench. Using a medium width grip (a grip that is slightly wider than shoulder width), lift the bar from the rack and hold it straight over you with your arms straight. This will be your starting position.','While keeping the arms straight, lift the bar by protracting your shoulder blades, raising the shoulders from the bench as you breathe out.','Bring back the bar to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['chest'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Rear Delt Row', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Stand up straight while holding a barbell using a wide (higher than shoulder width) and overhand (palms facing your body) grip.','Bend knees slightly and bend over as you keep the natural arch of your back. Let the arms hang in front of you as they hold the bar. Once your torso is parallel to the floor, flare the elbows out and away from your body. Tip: Your torso and your arms should resemble the letter T. Now you are ready to begin the exercise.','While keeping the upper arms perpendicular to the torso, pull the barbell up towards your upper chest as you squeeze the rear delts and you breathe out. Tip: When performed correctly, this exercise should resemble a bench press in reverse. Also, refrain from using your biceps to do the work. Focus on targeting the rear delts; the arms should only act as hooks.','Slowly go back to the initial position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['biceps','lats','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bradford/Rocky Presses', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Sit on a Military Press Bench with a bar at shoulder level with a pronated grip (palms facing forward). Tip: Your grip should be wider than shoulder width and it should create a 90-degree angle between the forearm and the upper arm as the barbell goes down. This is your starting position.','Once you pick up the barbell with the correct grip, lift the bar up over your head by locking your arms.','Now lower the bar down to the back of the head slowly as you inhale.','Lift the bar back up to the starting position as you exhale.','Lower the bar down to the starting position slowly as you inhale. This is one repetition.','Alternate in this manner until you complete the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Internal Rotation', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit next to a low pulley sideways (with legs stretched in front of you or crossed) and grasp the single hand cable attachment with the arm nearest to the cable. Tip: If you can adjust the pulley''s height, you can use a flat bench to sit on instead.','Position the elbow against your side with the elbow bent at 90° and the arm pointing towards the pulley. This will be your starting position.','Pull the single hand cable attachment toward your body by internally rotating your shoulder until your forearm is across your abs. You will be creating an imaginary semi-circle. Tip: The forearm should be perpendicular to your torso at all times.','Slowly go back to the initial position.','Repeat for the recommended amount of repetitions and then repeat the movement with the next arm.'], ARRAY['shoulders'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Rope Rear-Delt Rows', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit in the same position on a low pulley row station as you would if you were doing seated cable rows for the back.','Attach a rope to the pulley and grasp it with an overhand grip. Your arms should be extended and parallel to the floor with the elbows flared out.','Keep your lower back upright and slide your hips back so that your knees are slightly bent. This will be your starting position.','Pull the cable attachment towards your upper chest, just below the neck, as you keep your elbows up and out to the sides. Continue this motion as you exhale until the elbows travel slightly behind the back. Tip: Keep your upper arms horizontal, perpendicular to the torso and parallel to the floor throughout the motion.','Go back to the initial position where the arms are extended and the shoulders are stretched forward. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['biceps','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Shoulder Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Move the cables to the bottom of the towers and select an appropriate weight.','Stand directly in between the uprights. Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.','Keeping your head and chest up, extend through the elbow to press the handles directly over head.','After pausing at the top, return to the starting position and repeat.'], ARRAY['shoulders'], ARRAY['triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Raise', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Grab a dumbbell in each arm and stand up straight with your arms extended by your sides with a slight bend at the elbows and your back straight. This will be your starting position. Tip: The dumbbell should be next to your thighs with the palm of your hands facing back.','Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be to the side of the body as you move them up. Continue to lift it until the dumbbells are nearly in line with your chin. Tip: Your elbows should drive the motion. As you lift the dumbbell, your elbow should always be higher than your forearm. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['biceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Kettlebell Pirate Ships', 'kettlebells', true, 'kettlebells', 'beginner', 'push', 'compound', ARRAY['With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position.','Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion.','Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height.','Repeat for the desired amount of repetitions.'], ARRAY['shoulders'], ARRAY['abdominals'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Leverage Shoulder Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the shoulders at the beginning of the motion. Your chest and head should be up and handles held with a pronated grip. This will be your starting position.','Press the handles upward by extending through the elbow.','After a brief pause at the top, return the weight to just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.'], ARRAY['shoulders'], ARRAY['triceps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Low Pulley Row To Neck', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit on a low pulley row machine with a rope attachment.','Grab the ends of the rope using a palms-down grip and sit with your back straight and your knees slightly bent. Tip: Keep your back almost completely vertical and your arms fully extended in front of you. This will be your starting position.','While keeping your torso stationary, lift your elbows and start bending them as you pull the rope towards your neck while exhaling. Throughout the movement your upper arms should remain parallel to the floor. Tip: Continue this motion until your hands are almost next to your ears (the forearms will not be parallel to the floor at the end of the movement as they will be angled a bit upwards) and your elbows are out away from your sides.','After holding for a second or so at the contracted position, come back slowly to the starting position as you inhale. Tip: Again, during no part of the movement should the torso move.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['biceps','middle back','traps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Clean Shrug', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.','Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a clean, avoid overloading to the point that the execution slows down.'], ARRAY['traps'], ARRAY['forearms','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Smith Machine Upright Row', 'machine', true, 'machine', 'beginner', 'pull', 'compound', ARRAY['To begin, set the bar on the smith machine to a height that is around the middle of your thighs. Once the correct height is chosen and the bar is loaded, grasp the bar using a pronated (palms forward) grip that is shoulder width apart. You may need some wrist wraps if using a significant amount of weight.','Lift the barbell up and fully extend your arms with your back straight. There should be a slight bend at the elbows. This is the starting position.','Use your side shoulders to lift the bar as you exhale. The bar should be close to the body as you move it up. Continue to lift it until it nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the bar, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the bar back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY['biceps','middle back','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Standing Dumbbell Upright Row', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'compound', ARRAY['Grasp a dumbbell in each hand with a pronated (palms forward) grip that is slightly less than shoulder width. The dumbbells should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.','Use your side shoulders to lift the dumbbells as you exhale. The dumbbells should be close to the body as you move it up and the elbows should drive the motion. Continue to lift them until they nearly touch your chin. Tip: Your elbows should drive the motion. As you lift the dumbbells, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the dumbbells back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY['biceps','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Kettlebell Sumo High Pull', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place a kettlebell on the ground between your feet. Position your feet in a wide stance, and grasp the kettlebell with two hands. Set your hips back as far as possible, with your knees bent. Keep your chest and head up. This will be your starting position.','Begin by extending the hips and knees, simultaneously pulling the kettlebell to your shoulders, raising your elbows as you do so. Reverse the motion to return to the starting position.'], ARRAY['traps'], ARRAY['adductors','glutes','hamstrings','quadriceps','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Snatch Shrug', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin with a wide grip, with the bar hanging at the mid thigh position. You can use a hook or overhand grip. Your back should be straight and inclined slightly forward.','Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a snatch, avoid overloading to the point that the execution slows down.'], ARRAY['traps'], ARRAY['forearms','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Upright Cable Row', 'cable', true, 'cable', 'intermediate', 'pull', 'compound', ARRAY['Grasp a straight bar cable attachment that is attached to a low pulley with a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The bar should be resting on top of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.','Use your side shoulders to lift the cable bar as you exhale. The bar should be close to the body as you move it up. Continue to lift it until it nearly touches your chin. Tip: Your elbows should drive the motion. As you lift the bar, your elbows should always be higher than your forearms. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the bar back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY['shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Shrug', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up straight with your feet at shoulder width as you hold a barbell with both hands in front of you using a pronated grip (palms facing the thighs). Tip: Your hands should be a little wider than shoulder width apart. You can use wrist wraps for this exercise for a better grip. This will be your starting position.','Raise your shoulders up as far as you can go as you breathe out and hold the contraction for a second. Tip: Refrain from trying to lift the barbell by using your biceps.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Barbell Shrug Behind The Back', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up straight with your feet at shoulder width as you hold a barbell with both hands behind your back using a pronated grip (palms facing back). Tip: Your hands should be a little wider than shoulder width apart. You can use wrist wraps for this exercise for better grip. This will be your starting position.','Raise your shoulders up as far as you can go as you breathe out and hold the contraction for a second. Tip: Refrain from trying to lift the barbell by using your biceps. The arms should remain stretched out at all times.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY['forearms','middle back'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Cable Shrugs', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Grasp a cable bar attachment that is attached to a low pulley with a shoulder width or slightly wider overhand (palms facing down) grip.','Stand erect close to the pulley with your arms extended in front of you holding the bar. This will be your starting position.','Lift the bar by elevating the shoulders as high as possible as you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the bar. Only the shoulders should be moving up and down.','Lower the bar back to the original position.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Calf-Machine Shoulder Shrug', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Position yourself on the calf machine so that the shoulder pads are above your shoulders. Your torso should be straight with the arms extended normally by your side. This will be your starting position.','Raise your shoulders up towards your ears as you exhale and hold the contraction for a full second.','Slowly return to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dumbbell Shrug', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand erect with a dumbbell on each hand (palms facing your torso), arms extended on the sides.','Lift the dumbbells by elevating the shoulders as high as possible while you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the dumbbells. Only the shoulders should be moving up and down.','Lower the dumbbells back to the original position.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Leverage Shrug', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Load the pins to an appropriate weight. Position yourself directly between the handles.','Grasp the top handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up.','Drive through the floor with your heels, extending your hips and knees as you rise to a standing position. Keep your arms straight throughout the movement, finishing with your shoulders back. This will be your starting position.','Raise the weight by shrugging the shoulders towards your ears, moving straight up and down.','Pause at the top of the motion, and then return the weight to the starting position.'], ARRAY['traps'], ARRAY['forearms'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bench Dips', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['For this exercise you will need to place a bench behind your back. With the bench perpendicular to your body, and while looking away from it, hold on to the bench on its edge with the hands fully extended, separated at shoulder width. The legs will be extended forward, bent at the waist and perpendicular to your torso. This will be your starting position.','Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.','Using your triceps to bring your torso up again, lift yourself back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip Barbell Bench Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Lie back on a flat bench. Using a close grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that - as opposed to a regular bench press - you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip Dumbbell Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Place a dumbbell standing up on a flat bench.','Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench with only your shoulders lying on the surface. Hips should be below the bench and your legs bent with your feet firmly on the floor.','Grasp the dumbbell with both hands and hold it straight over your chest at arm''s length. Both palms should be pressing against the underside of the sides of the dumbbell. This will be your starting position.','Initiate the movement by lowering the dumbbell to your chest.','Return to the starting position by extending the elbows.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Close-Grip EZ-Bar Press', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'push', 'compound', ARRAY['Lie on a flat bench with an EZ bar loaded to an appropriate weight.','Using a narrow grip lift the bar and hold it straight over your torso with your elbows in. The arms should be perpendicular to the floor. This will be your starting position.','Now lower the bar down to your lower chest as you breathe in. Keep the elbows in as you perform this movement.','Using the triceps to push the bar back up, press it back to the starting position by extending the elbows as you exhale.','Repeat.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dip Machine', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Sit securely in a dip machine, select the weight and firmly grasp the handles.','Now keep your elbows in at your sides in order to place emphasis on the triceps. The elbows should be bent at a 90 degree angle.','As you contract the triceps, extend your arms downwards as you exhale. Tip: At the bottom of the movement, focus on keeping a little bend in your arms to keep tension on the triceps muscle.','Now slowly let your arms come back up to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Dips - Triceps Version', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['To get into the starting position, hold your body at arm''s length with your arms nearly locked above the bars.','Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm.','Then, exhale and push your torso back up using your triceps to bring your body back to the starting position.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Incline Push-Up Close-Grip', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands next to one another on the bar.','Position your feet back from the bar with arms and body straight. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('JM Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Start the exercise the same way you would a close grip bench press. You will lie on a flat bench while holding a barbell at arms length (fully extended) with the elbows in. However, instead of having the arms perpendicular to the torso, make sure the bar is set in a direct line above the upper chest. This will be your starting position.','Now beginning from a fully extended position lower the bar down as if performing a lying triceps extension. Inhale as you perform this movement. When you reach the half way point, let the bar roll back about one inch by moving the upper arms towards your legs until they are perpendicular to the torso. Tip: Keep the bend at the elbows constant as you bring the upper arms forward.','As you exhale, press the bar back up by using the triceps to perform a close grip bench press.','Now go back to the starting position and start over.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Smith Machine Close-Grip Bench Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place a flat bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a close and pronated grip (palms facing forward) that is around shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, lock the bar back in the rack.'], ARRAY['triceps'], ARRAY['chest','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bench Press - Powerlifting', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin by lying on the bench, getting your head beyond the bar if possible. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.','However wide your grip, it should cover the ring on the bar. Pull the bar out of the rack without protracting your shoulders. Focus on squeezing the bar and trying to pull it apart.','Lower the bar to your lower chest or upper stomach. The bar, wrist, and elbow should stay in line at all times.','Pause when the barbell touches your torso, and then drive the bar up with as much force as possible. The elbows should be tucked in until lockout.'], ARRAY['triceps'], ARRAY['chest','forearms','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Bench Press with Chains', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['Adjust the leader chain, shortening it to the desired length.Place the chains on the sleeves of the bar.','Lying on the bench, get your head beyond the bar if possible. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. However wide your grip, it should cover the ring on the bar.','Pull the bar out of the rack without protracting your shoulders. Focus on squeezing the bar and trying to pull it apart. Lower the bar to your lower chest or upper stomach. The bar, wrist, and elbow should stay in line at all times.','Pause when the barbell touches your torso, and then drive the bar up with as much force as possible. The elbows should be tucked in until lockout.'], ARRAY['triceps'], ARRAY['chest','lats','shoulders'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles)
VALUES ('Board Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Begin by lying on the bench, getting your head beyond the bar if possible. One to five boards, made out of 2x6''s, can be screwed together and held in place by a training partner, bands, or just tucked under your shirt.','Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.','You can take a standard bench grip, or shoulder width to focus on the triceps. Pull the bar out of the rack without protracting your shoulders. The bar, wrist, and elbow should stay in line at all times. Focus on squeezing the bar and trying to pull it apart.','Lower the bar to the boards, and then drive the bar up with as much force as possible. The elbows should be tucked in until lockout.'], ARRAY['triceps'], ARRAY['chest','forearms','lats','shoulders'])
ON CONFLICT DO NOTHING;

